import{_ as t,o as a,c as i,ae as o}from"./chunks/framework.6gkcVjOI.js";const u=JSON.parse('{"title":"Design Philosophy","description":"Deep dive into the intelligence/reliability separation — what the model does vs. what the harness guarantees","frontmatter":{"title":"Design Philosophy","description":"Deep dive into the intelligence/reliability separation — what the model does vs. what the harness guarantees"},"headers":[],"relativePath":"architecture/design-philosophy.md","filePath":"architecture/design-philosophy.md","lastUpdated":1775221353000}'),n={name:"architecture/design-philosophy.md"};function r(s,e,l,h,d,c){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="design-philosophy" tabindex="-1">Design Philosophy <a class="header-anchor" href="#design-philosophy" aria-label="Permalink to &quot;Design Philosophy&quot;">​</a></h1><h2 id="the-core-principle" tabindex="-1">The Core Principle <a class="header-anchor" href="#the-core-principle" aria-label="Permalink to &quot;The Core Principle&quot;">​</a></h2><p><strong>Model provides intelligence, harness provides reliability</strong> — this is not a marketing slogan. It is an architectural constraint that shapes every line of code in go-code.</p><p>The principle emerges from a fundamental observation: large language models are remarkably capable at reasoning, planning, and generating appropriate responses, but they lack the properties required for safe, reliable system operation. They have no concept of timeouts, no understanding of resource constraints, no built-in safety guarantees, and no memory across sessions. Meanwhile, traditional software systems excel at these reliability properties but cannot reason about user intent or choose appropriate actions.</p><p>go-code sits at this boundary. The model handles the cognitive work — understanding what the user wants, deciding which tools to call, interpreting results, planning the next step. The harness handles the reliability work — ensuring operations execute within bounds, protecting against resource exhaustion, maintaining session state, and enforcing security boundaries.</p><p>This separation is not merely convenient. It is necessary because <strong>the model can be wrong, but the harness must never fail</strong>.</p><h2 id="what-the-model-provides-intelligence" tabindex="-1">What the Model Provides: Intelligence <a class="header-anchor" href="#what-the-model-provides-intelligence" aria-label="Permalink to &quot;What the Model Provides: Intelligence&quot;">​</a></h2><p>When we say the model provides &quot;intelligence,&quot; we mean a specific set of capabilities that go-code delegates to the LLM:</p><h3 id="intent-understanding" tabindex="-1">Intent Understanding <a class="header-anchor" href="#intent-understanding" aria-label="Permalink to &quot;Intent Understanding&quot;">​</a></h3><p>The model interprets natural language input and extracts what the user is actually trying to accomplish. &quot;Make this function faster&quot; is not a precise instruction — the model must understand what &quot;faster&quot; means in context, which function is being referenced, and what performance characteristics currently exist. This is an intelligence task that no amount of rule-based parsing can replace.</p><h3 id="tool-selection" tabindex="-1">Tool Selection <a class="header-anchor" href="#tool-selection" aria-label="Permalink to &quot;Tool Selection&quot;">​</a></h3><p>Given an available toolset (Read, Write, Edit, Glob, Grep, Bash, plus any MCP tools), the model decides which tools to call and in what order. This requires understanding tool capabilities, matching them to the current task, and forming a plan. The harness provides the list of available tools, but the model determines which ones to use.</p><h3 id="result-interpretation" tabindex="-1">Result Interpretation <a class="header-anchor" href="#result-interpretation" aria-label="Permalink to &quot;Result Interpretation&quot;">​</a></h3><p>Tool outputs are not self-explanatory. A grep search returns lines of text; the model must interpret whether those results indicate success, failure, or partial progress. A file write operation returns a simple confirmation; the model must decide whether to verify the write, proceed to the next step, or report completion to the user.</p><h3 id="next-step-planning" tabindex="-1">Next-Step Planning <a class="header-anchor" href="#next-step-planning" aria-label="Permalink to &quot;Next-Step Planning&quot;">​</a></h3><p>The agent loop is iterative. After each tool execution, the model must decide: continue with the next step, try a different approach, ask for clarification, or declare the task complete. This is a planning and reasoning task that requires understanding the overall goal and current progress.</p><p>These four capabilities — intent understanding, tool selection, result interpretation, and next-step planning — constitute what we mean by &quot;intelligence&quot; in this architectural context. They are the cognitive work that the LLM performs, and they are impossible to implement with deterministic code.</p><h2 id="what-the-harness-provides-reliability" tabindex="-1">What the Harness Provides: Reliability <a class="header-anchor" href="#what-the-harness-provides-reliability" aria-label="Permalink to &quot;What the Harness Provides: Reliability&quot;">​</a></h2><p>Reliability is not a single property but a collection of guarantees that traditional software systems have long provided:</p><h3 id="permission-control" tabindex="-1">Permission Control <a class="header-anchor" href="#permission-control" aria-label="Permalink to &quot;Permission Control&quot;">​</a></h3><p>The model may request any operation, but the harness decides which operations actually execute. Permission control is not advisory — it is a hard gate that blocks operations the user has not approved. The model might ask to delete all files in the project, but the harness intercepts this request and only proceeds if the user&#39;s permission policy allows it.</p><p>This is the most critical reliability property because the model operates with the user&#39;s full privileges. Without permission control, an AI agent would be indistinguishable from a malicious script.</p><h3 id="timeout-protection" tabindex="-1">Timeout Protection <a class="header-anchor" href="#timeout-protection" aria-label="Permalink to &quot;Timeout Protection&quot;">​</a></h3><p>The model has no concept of time. It might call a grep search over a million files and wait indefinitely for results. It might execute a shell command that never terminates. The harness enforces timeout bounds — if a tool doesn&#39;t complete within the configured duration, it is terminated and an error is returned to the model.</p><p>Without timeout protection, a single misbehaving tool could hang the entire session indefinitely.</p><h3 id="output-truncation" tabindex="-1">Output Truncation <a class="header-anchor" href="#output-truncation" aria-label="Permalink to &quot;Output Truncation&quot;">​</a></h3><p>Tool outputs can be arbitrarily large. Reading a binary file, running a command that produces megabytes of output, or grep searching a massive codebase could produce results larger than the context window. The harness truncates tool outputs to prevent them from consuming the entire available context.</p><p>This is not merely a performance optimization — it is a correctness guarantee. Without truncation, the system could fail to provide the model with the information it needs to complete the task.</p><h3 id="session-persistence" tabindex="-1">Session Persistence <a class="header-anchor" href="#session-persistence" aria-label="Permalink to &quot;Session Persistence&quot;">​</a></h3><p>The model is stateless between API calls. The harness maintains conversation history across turns and can persist sessions to disk for later resumption. This allows the user to disconnect and reconnect without losing progress on a long-running task.</p><h3 id="error-recovery" tabindex="-1">Error Recovery <a class="header-anchor" href="#error-recovery" aria-label="Permalink to &quot;Error Recovery&quot;">​</a></h3><p>Tools can fail for reasons unrelated to the model&#39;s reasoning — network timeouts, file permission issues, invalid tool inputs. The harness catches these errors, formats them appropriately, and presents them to the model in a way that enables recovery. The model can decide to retry, try a different approach, or report the error to the user.</p><h2 id="why-this-separation-matters" tabindex="-1">Why This Separation Matters <a class="header-anchor" href="#why-this-separation-matters" aria-label="Permalink to &quot;Why This Separation Matters&quot;">​</a></h2><p>The separation of intelligence and reliability is not an implementation detail — it is a fundamental architectural requirement that stems from the nature of current AI systems.</p><h3 id="the-model-can-be-wrong" tabindex="-1">The Model Can Be Wrong <a class="header-anchor" href="#the-model-can-be-wrong" aria-label="Permalink to &quot;The Model Can Be Wrong&quot;">​</a></h3><p>LLMs are probabilistic systems. They can hallucinate, misinterpret instructions, choose suboptimal tools, and make mistakes. A model might:</p><ul><li>Call the wrong tool for the task</li><li>Misinterpret a tool&#39;s output</li><li>Enter an infinite loop of tool calls</li><li>Misunderstand the user&#39;s intent</li></ul><p>These failures are expected and should be handled gracefully. The harness cannot prevent model errors, but it can contain their impact.</p><h3 id="the-harness-must-never-fail" tabindex="-1">The Harness Must Never Fail <a class="header-anchor" href="#the-harness-must-never-fail" aria-label="Permalink to &quot;The Harness Must Never Fail&quot;">​</a></h3><p>Unlike the model, the harness is deterministic software. It should never:</p><ul><li>Crash during permission checks</li><li>Fail to enforce timeouts</li><li>Lose user data due to session failures</li><li>Allow unauthorized operations</li><li>Produce unpredictable behavior</li></ul><p>These are the same reliability guarantees that any production system must provide. The harness&#39;s job is to maintain these guarantees regardless of what the model does.</p><h3 id="the-interface-between-them" tabindex="-1">The Interface Between Them <a class="header-anchor" href="#the-interface-between-them" aria-label="Permalink to &quot;The Interface Between Them&quot;">​</a></h3><p>The model and harness communicate through a well-defined interface. The model receives tool definitions (name, description, input schema) and decides which tools to call. The harness executes tools and returns structured results (text output, errors, success/failure status).</p><p>This interface is intentionally narrow. The model cannot bypass the harness, cannot inspect harness internals, and cannot modify harness behavior. The harness is a hard boundary, not a soft layer.</p><h2 id="design-decisions" tabindex="-1">Design Decisions <a class="header-anchor" href="#design-decisions" aria-label="Permalink to &quot;Design Decisions&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Decision</th><th>Rationale</th><th>Trade-off</th></tr></thead><tbody><tr><td><strong>Three-tier permission model</strong></td><td>Binary allow/deny is insufficient for varied development workflows</td><td>More complex configuration, but enables practical use</td></tr><tr><td><strong>Glob rule matching for paths</strong></td><td>Allows fine-grained control over which files can be modified</td><td>Requires users to understand glob patterns</td></tr><tr><td><strong>250-character tool descriptions</strong></td><td>Forces discipline in capability communication; prevents context bloat</td><td>May omit useful tool details</td></tr><tr><td><strong>MAX_TURNS = 50</strong></td><td>Prevents resource exhaustion from infinite loops</td><td>Complex tasks may need more iterations</td></tr><tr><td><strong>Three-tier message compaction</strong></td><td>Preserves semantic content while managing token limits</td><td>Compression is lossy; some context may be lost</td></tr><tr><td><strong>Pure Go implementation</strong></td><td>No runtime dependencies; consistent performance</td><td>Less flexible than interpreted languages</td></tr><tr><td><strong>MCP as external adapter</strong></td><td>Protocol-agnostic tool discovery; ecosystem integration</td><td>MCP servers add external dependencies</td></tr></tbody></table><h2 id="comparison-with-other-approaches" tabindex="-1">Comparison with Other Approaches <a class="header-anchor" href="#comparison-with-other-approaches" aria-label="Permalink to &quot;Comparison with Other Approaches&quot;">​</a></h2><p>go-code&#39;s architecture can be contrasted with several alternative approaches to AI-assisted software development:</p><h3 id="chatbot-paradigm" tabindex="-1">Chatbot Paradigm <a class="header-anchor" href="#chatbot-paradigm" aria-label="Permalink to &quot;Chatbot Paradigm&quot;">​</a></h3><p>In a pure chatbot, the LLM generates text responses without taking direct actions. The user reads the response and executes commands manually. This provides maximum safety but minimum automation.</p><p><strong>go-code&#39;s position</strong>: The model takes actions directly, with the harness ensuring safety through permission checks and timeout protection.</p><h3 id="script-runner-paradigm" tabindex="-1">Script Runner Paradigm <a class="header-anchor" href="#script-runner-paradigm" aria-label="Permalink to &quot;Script Runner Paradigm&quot;">​</a></h3><p>In a script runner, predefined scripts execute without LLM involvement. The LLM generates script arguments but has no control over the execution flow.</p><p><strong>go-code&#39;s position</strong>: The model controls the execution flow, choosing which tools to call and in what order. The harness ensures execution stays within bounds.</p><h3 id="full-ide-paradigm" tabindex="-1">Full IDE Paradigm <a class="header-anchor" href="#full-ide-paradigm" aria-label="Permalink to &quot;Full IDE Paradigm&quot;">​</a></h3><p>In a full IDE, the AI has complete access to the development environment, including file system, build tools, and debugging capabilities. Safety is managed through user supervision rather than automated checks.</p><p><strong>go-code&#39;s position</strong>: Permission control is enforced automatically. Human-in-the-loop approval is available but not required for routine operations.</p><h3 id="agent-framework-vs-agent-product" tabindex="-1">Agent Framework vs. Agent Product <a class="header-anchor" href="#agent-framework-vs-agent-product" aria-label="Permalink to &quot;Agent Framework vs. Agent Product&quot;">​</a></h3><p>Many &quot;agent frameworks&quot; provide just the agent loop and leave safety, persistence, and permission to the user. This is appropriate for experimentation but unsuitable for production use.</p><p><strong>go-code&#39;s position</strong>: go-code is an agent <em>product</em> that ships with all reliability features included. Users can configure but not remove safety guarantees.</p><h2 id="the-philosophy-in-practice" tabindex="-1">The Philosophy in Practice <a class="header-anchor" href="#the-philosophy-in-practice" aria-label="Permalink to &quot;The Philosophy in Practice&quot;">​</a></h2><p>When building features in go-code, the intelligence/reliability separation serves as a decision-making framework:</p><ul><li>If a capability requires <strong>understanding user intent</strong> → model responsibility</li><li>If a capability requires <strong>choosing between options</strong> → model responsibility</li><li>If a capability requires <strong>guaranteeing safety</strong> → harness responsibility</li><li>If a capability requires <strong>resource management</strong> → harness responsibility</li><li>If a capability requires <strong>persistence across sessions</strong> → harness responsibility</li></ul><p>This framework isn&#39;t perfect — some capabilities straddle the boundary. But it provides a consistent heuristic for architectural decisions.</p><h2 id="related-documentation" tabindex="-1">Related Documentation <a class="header-anchor" href="#related-documentation" aria-label="Permalink to &quot;Related Documentation&quot;">​</a></h2><ul><li><a href="./overview.html">Architecture Overview</a> — System components and data flow</li><li><a href="./agent-loop.html">Agent Loop</a> — State machine mechanics and execution cycle</li><li><a href="./tools.html#permission-system">Permission System</a> — Three-tier model and policy configuration</li></ul>',67)])])}const m=t(n,[["render",r]]);export{u as __pageData,m as default};
